import json
import sys
from pathlib import Path
from vibe.harness.memory.eval_store import EvalStore

def generate_report(current_score: float, baseline_score: float) -> tuple[str, bool]:
    passed_regression = current_score >= (baseline_score * 0.95)
    
    status = "✅ Passed" if passed_regression else "❌ Regression Detected"
    
    md = f"""# Vibe Agent Eval Report

## Result: {status}

- **Current Score**: {current_score:.2%}
- **Baseline Score**: {baseline_score:.2%}
- **Threshold**: {(baseline_score * 0.95):.2%} (5% allowed drop)

*Generated by CI automatically.*
"""
    return md, passed_regression

def main():
    store = EvalStore()
    summary = store.summary()
    score = summary['score']
    
    baseline_score = 1.0
    baseline_path = Path('docs/baseline_scorecard.json')
    if baseline_path.exists():
        with open(baseline_path, 'r', encoding='utf-8') as f:
            baseline_data = json.load(f)
            baseline_score = baseline_data.get('overall_score', 1.0)
            
    md_content, passed = generate_report(score, baseline_score)
    
    # Write to a file for GitHub Actions
    with open('eval_report.md', 'w', encoding='utf-8') as f:
        f.write(md_content)
        
    print(f"Eval score: {score:.2%} (baseline: {baseline_score:.2%})")
    if not passed:
        print("Failing CI due to regression.")
        sys.exit(1)
    else:
        print("Eval within acceptable bounds.")
        sys.exit(0)

if __name__ == "__main__":
    main()
